#!/usr/bin/env node
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const HERE = dirname(fileURLToPath(import.meta.url));
const ROOT = join(HERE, "..");

export function renderProductionRouting({ router, registry, runtime }) {
  const profileName = runtime.productionProfile;
  const profile = router[profileName];
  if (!profile) throw new Error(`production profile ${profileName} is missing`);
  const lines = [
    "# Production Routing",
    "",
    "> Generated by `node scripts/routing-consistency.mjs --write`. Do not edit manually.",
    "",
    `Active profile: \`${profileName}\``,
    "",
    "| Category | Plane | Alias | Pinned model | Fallback |",
    "|---|---|---|---|---|",
  ];
  for (const [category, rule] of Object.entries(profile.categories)) {
    const version = registry.models[rule.model]?.version || "MISSING";
    const fallback = rule.fallback
      ? `${rule.fallback.plane}/${rule.fallback.model} (${registry.models[rule.fallback.model]?.version || "MISSING"})`
      : "-";
    lines.push(`| ${category} | ${rule.plane} | ${rule.model} | ${version} | ${fallback} |`);
  }
  lines.push("", `Unknown or low-confidence tasks: \`${profile.default}\` (CLI judgment resolves to the governed orchestrator route).`, "");
  return lines.join("\n");
}

export function consistencyErrors({ router, registry, runtime, files }) {
  const errors = [];
  const profile = router[runtime.productionProfile];
  if (!profile) return [`missing production profile ${runtime.productionProfile}`];
  for (const [category, rule] of Object.entries(profile.categories || {})) {
    if (!registry.models[rule.model]) errors.push(`${category}: missing model ${rule.model}`);
    if (rule.fallback && !registry.models[rule.fallback.model]) errors.push(`${category}: missing fallback ${rule.fallback.model}`);
  }
  const extract = profile.categories?.extract;
  const docQa = profile.categories?.["doc-qa"];
  if (extract?.model !== "kimi-k2.5-ikey" || docQa?.model !== "kimi-k2.5-ikey") errors.push("production extract/doc-qa must route to Kimi K2.5");
  if (extract?.fallback?.model !== "deepseek-ikey" || docQa?.fallback?.model !== "deepseek-ikey") errors.push("production extract/doc-qa must fail over to DeepSeek");
  if (!files.piWorker.includes('kimi|kimi25) MODEL="ikey/test/kimi-k2.5"')) errors.push("pi-worker kimi alias is not K2.5");
  if (!files.gatewayCall.includes("kimi: 'test/kimi-k2.5'")) errors.push("gateway kimi alias is not K2.5");
  return errors;
}

export function loadInputs(root = ROOT) {
  return {
    router: JSON.parse(readFileSync(join(root, "config", "router.json"), "utf8")),
    registry: JSON.parse(readFileSync(join(root, "config", "models.json"), "utf8")),
    runtime: JSON.parse(readFileSync(join(root, "config", "runtime.json"), "utf8")),
    files: {
      piWorker: readFileSync(join(root, "scripts", "pi-worker.sh"), "utf8"),
      gatewayCall: readFileSync(join(root, "scripts", "gateway-call.mjs"), "utf8"),
    },
  };
}

async function main() {
  const inputs = loadInputs();
  const errors = consistencyErrors(inputs);
  if (errors.length) throw new Error(errors.join("; "));
  const output = renderProductionRouting(inputs);
  const target = join(ROOT, "docs", "production-routing.md");
  if (process.argv.includes("--write")) writeFileSync(target, output);
  else if (readFileSync(target, "utf8") !== output) throw new Error("docs/production-routing.md is stale; run with --write");
  console.log(`routing consistency: OK (${inputs.runtime.productionProfile})`);
}

if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
  main().catch((err) => { console.error(`routing consistency: FAILED: ${err.message}`); process.exit(1); });
}
